package com.company.traceuploader.metadata;
import com.company.traceuploader.config.AgentConfig;import com.company.traceuploader.model.TraceFileMetadata;import com.company.traceuploader.scanner.SealedFile;import org.junit.jupiter.api.*;import java.nio.file.*;import static org.junit.jupiter.api.Assertions.*;
class MetadataServiceTest { @TempDir Path dir; @Test void parsesNameAndBuildsPaths() throws Exception { Path f=dir.resolve("trace-payment-dev-local-c1-host001-pid123-bootlocal-20260610T100000-20260610T100500-seq000001.jsonl"); Files.writeString(f,"one\ntwo\n"); Path d=dir.resolve(f.getFileName()+".done"); Files.createFile(d); AgentConfig c=new AgentConfig(); c.hdfs.bucketCount=16; MetadataService svc=new MetadataService(c,new ChecksumService(),new FileIdGenerator()); TraceFileMetadata m=svc.build(new SealedFile(f,d),1); assertEquals("payment",m.app()); assertEquals(2,m.recordCount()); assertEquals(8,m.sizeBytes()); assertTrue(m.checksum().startsWith("sha256:")); assertTrue(m.hdfsFinalPath().contains("app=payment/dt=2026-06-10/hour=10/region=local/bucket=")); assertTrue(m.hdfsStagingPath().contains("attempt_1.tmp")); } }
